@cope,

I think `includes` is faster and more effective than `difference`, because the first only checks for the existence of a value rather than creating a new array with new values.

Your snippet looks good! But it says to search for `values` within `array`, when you actually want to check an "intersection" of values between `values` and `array`. To clarify:

```js
function baseSame (array1, array2) {
    for (const x of array1) {
        if (includes(array2, x) === false) {
            return false;
        }
    }

    return true;
}

function same (array1, array2) {
    if (array1 === array2) {
        return true;
    }
    
    return array1.length === array2.length && baseSame(array1, array2) && baseSame(array2, array1);
}
```
How about adding also `values === array` to check whether both arguments point to the same object?

@zaclummys I agree.

Would this be acceptable?
```javascript
import forEach from './forEach.js'
import includes from './.includes.js'

function containsAll (a, b) {
    let all = true;
    forEach(b, x => all = includes(a, x));
    return all;
}

function same (a, b) {
    return a.length === b.length && (a === b || (containsAll(a, b) && containsAll(b, a)));
}
```

